#include <stdio.h>
#include <string.h>
#include <stdlib.h>

// Simple hash function (for educational purposes - not secure)
unsigned long simple_hash(char *str) {
    unsigned long hash = 5381;
    int c;
    while (c = *str++) {
        hash = ((hash << 5) + hash) + c; // hash * 33 + c
    }
    return hash;
}

// Generate random salt
void generate_salt(char *salt, int length) {
    const char charset[] = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    for (int i = 0; i < length; i++) {
        salt[i] = charset[rand() % (sizeof(charset) - 1)];
    }
    salt[length] = '\0';
}

int main() {
    char password[100];
    char salt[17];
    char salted_password[117];

    printf("Enter password: ");
    scanf("%s", password);

    // Generate 16-character salt
    generate_salt(salt, 16);

    // Create salted password
    strcpy(salted_password, salt);
    strcat(salted_password, password);

    // Hash the salted password
    unsigned long hash = simple_hash(salted_password);

    printf("Salt: %s\n", salt);
    printf("Hash: %lu\n", hash);

    return 0;
}
